import { useState, useEffect, useCallback } from "react";

// Ã¢â€â‚¬Ã¢â€â‚¬ Types Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬

interface Market {
  id: string;
  title: string;
  probability: number;
  topOutcome: string;
  volume: number;
  source: "polymarket" | "kalshi";
  url: string;
  marketCount: number;
}

type Filter = "all" | "polymarket" | "kalshi";

// Ã¢â€â‚¬Ã¢â€â‚¬ Helpers Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬

function fmtVol(v: number): string {
  if (v >= 1_000_000_000) return `$${(v / 1_000_000_000).toFixed(1)}B`;
  if (v >= 1_000_000) return `$${(v / 1_000_000).toFixed(1)}M`;
  if (v >= 1_000) return `$${(v / 1_000).toFixed(1)}K`;
  return `$${Math.round(v)}`;
}

function probColor(p: number): string {
  if (p >= 70) return "#34d399";
  if (p >= 40) return "#fbbf24";
  return "#f87171";
}

// Ã¢â€â‚¬Ã¢â€â‚¬ Polymarket probability parser Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// outcomePrices is a JSON string: '["0.20","0.80"]'
// outcomes is a JSON string: '["Yes","No"]'
// They map 1:1. We want the "Yes" price.

function getPolyYesProb(market: any): number {
  // Only use outcomePrices Ã¢â‚¬â€ no fallbacks that could give wrong values
  if (!market.outcomePrices) return -1; // -1 means unknown

  try {
    const prices =
      typeof market.outcomePrices === "string"
        ? JSON.parse(market.outcomePrices)
        : market.outcomePrices;

    if (!Array.isArray(prices) || prices.length === 0) return -1;

    // Check outcomes to find which index is "Yes"
    let outcomes: string[] = ["Yes", "No"];
    if (market.outcomes) {
      try {
        outcomes =
          typeof market.outcomes === "string"
            ? JSON.parse(market.outcomes)
            : market.outcomes;
      } catch {}
    }

    // Find the "Yes" index
    const yesIdx = outcomes.findIndex(
      (o) => typeof o === "string" && o.toLowerCase() === "yes"
    );

    if (yesIdx >= 0 && prices[yesIdx] !== undefined) {
      const val = parseFloat(prices[yesIdx]);
      if (!isNaN(val) && val >= 0 && val <= 1) {
        return val * 100;
      }
    }

    // Default: index 0 is Yes (standard Polymarket format)
    const val = parseFloat(prices[0]);
    if (!isNaN(val) && val >= 0 && val <= 1) {
      return val * 100;
    }

    return -1;
  } catch {
    return -1;
  }
}

// Ã¢â€â‚¬Ã¢â€â‚¬ Polymarket Fetcher Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬

async function fetchPolymarket(): Promise<Market[]> {
  try {
    const url =
      "https://gamma-api.polymarket.com/events?closed=false&order=volume&ascending=false&limit=20";
    const res = await fetch("/api/proxy?url=" + encodeURIComponent(url));
    if (!res.ok) throw new Error(`Polymarket HTTP ${res.status}`);
    const events = await res.json();

    if (!Array.isArray(events)) return [];

    // Debug first event
    if (events.length > 0) {
      const e = events[0];
      const m0 = e.markets?.[0];
      console.log("POLY first event:", e.title, "volume:", e.volume, "markets:", e.markets?.length);
      if (m0) {
        console.log("POLY first market:", {
          groupItemTitle: m0.groupItemTitle,
          outcomePrices: m0.outcomePrices,
          outcomes: m0.outcomes,
          lastTradePrice: m0.lastTradePrice,
        });
      }
    }

    return events
      .map((ev: any): Market | null => {
        try {
          const title = ev.title || ev.question || "Untitled";
          const slug = ev.slug || "";
          const markets = ev.markets || [];

          // Volume
          let totalVol = parseFloat(ev.volume || "0") || 0;
          if (totalVol === 0) {
            totalVol = markets.reduce(
              (s: number, m: any) => s + (parseFloat(m.volume || "0") || 0),
              0
            );
          }
          if (totalVol < 1) return null;

          // Probability
          let bestProb = -1;
          let bestOutcome = "Yes";

          if (markets.length === 0) {
            // No nested markets Ã¢â‚¬â€ try event-level outcomePrices
            const p = getPolyYesProb(ev);
            bestProb = p;
          } else if (markets.length === 1) {
            // Single binary market
            const p = getPolyYesProb(markets[0]);
            bestProb = p;
            bestOutcome = "Yes";
          } else {
            // Multi-outcome: find the market with the HIGHEST Yes probability
            for (const m of markets) {
              const p = getPolyYesProb(m);
              if (p > bestProb) {
                bestProb = p;
                bestOutcome =
                  m.groupItemTitle || m.title || m.question || "Top";
                if (bestOutcome.length > 35)
                  bestOutcome = bestOutcome.slice(0, 32) + "Ã¢â‚¬Â¦";
              }
            }
          }

          // If we couldn't determine probability, show 0
          if (bestProb < 0) bestProb = 0;

          return {
            id: `poly-${ev.id || slug}`,
            title,
            probability: Math.round(bestProb * 10) / 10,
            topOutcome: bestOutcome,
            volume: totalVol,
            source: "polymarket",
            url: `https://polymarket.com/event/${slug}`,
            marketCount: markets.length,
          };
        } catch {
          return null;
        }
      })
      .filter((m): m is Market => m !== null);
  } catch (err) {
    console.error("Polymarket fetch error:", err);
    return [];
  }
}

// Ã¢â€â‚¬Ã¢â€â‚¬ Kalshi probability parser Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Official fields from docs:
//   last_price_dollars: "0.5600"  (string, 0-1 in dollars)
//   yes_bid_dollars:    "0.5600"
//   yes_ask_dollars:    "0.5600"
//   yes_price:          56        (integer, cents 0-100)
//   volume:             1234      (integer, total contracts)
//   volume_fp:          "1234.00" (string, total contracts)

function getKalshiProb(market: any): number {
  // 1) Try last_price_dollars (string like "0.5600" Ã¢â€ â€™ 56%)
  const lpd = parseFloat(market.last_price_dollars || "");
  if (!isNaN(lpd) && lpd > 0 && lpd <= 1) {
    return lpd * 100;
  }

  // 2) Try yes_bid_dollars / yes_ask_dollars midpoint
  const ybd = parseFloat(market.yes_bid_dollars || "");
  const yad = parseFloat(market.yes_ask_dollars || "");
  if (!isNaN(ybd) && !isNaN(yad) && (ybd > 0 || yad > 0)) {
    const mid = ybd > 0 && yad > 0 ? (ybd + yad) / 2 : ybd || yad;
    if (mid > 0 && mid <= 1) return mid * 100;
  }

  // 3) Try yes_price (integer cents, 0-100)
  const yp = parseInt(market.yes_price);
  if (!isNaN(yp) && yp > 0 && yp <= 100) {
    return yp;
  }

  // 4) Try last_price (integer cents)
  const lp = parseInt(market.last_price);
  if (!isNaN(lp) && lp > 0 && lp <= 100) {
    return lp;
  }

  return 0;
}

function getKalshiVolume(market: any): number {
  // Try volume (integer) first, then volume_fp (string)
  const v = parseInt(market.volume);
  if (!isNaN(v) && v > 0) return v;

  const vfp = parseFloat(market.volume_fp || "");
  if (!isNaN(vfp) && vfp > 0) return vfp;

  return 0;
}

// Ã¢â€â‚¬Ã¢â€â‚¬ Kalshi Fetcher Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬

async function fetchKalshi(): Promise<Market[]> {
  try {
    const url =
      "https://api.elections.kalshi.com/trade-api/v2/events?status=open&with_nested_markets=true&limit=100";
    const res = await fetch("/api/proxy?url=" + encodeURIComponent(url));
    if (!res.ok) throw new Error(`Kalshi HTTP ${res.status}`);
    const data = await res.json();
    const events = data.events || [];

    if (!Array.isArray(events) || events.length === 0) return [];

    // Debug first event
    if (events[0]?.markets?.[0]) {
      const m = events[0].markets[0];
      console.log("KALSHI first event:", events[0].title);
      console.log("KALSHI first market ALL KEYS:", Object.keys(m));
      console.log("KALSHI first market VALUES:", {
        ticker: m.ticker,
        event_ticker: m.event_ticker,
        title: m.title,
        subtitle: m.subtitle,
        yes_price: m.yes_price,
        last_price: m.last_price,
        yes_bid: m.yes_bid,
        yes_ask: m.yes_ask,
        yes_bid_dollars: m.yes_bid_dollars,
        yes_ask_dollars: m.yes_ask_dollars,
        last_price_dollars: m.last_price_dollars,
        volume: m.volume,
        volume_fp: m.volume_fp,
        volume_24h_fp: m.volume_24h_fp,
        open_interest_fp: m.open_interest_fp,
      });
      console.log("KALSHI event fields:", Object.keys(events[0]));
    }

    const results: Market[] = [];

    for (const ev of events) {
      try {
        const title = ev.title || "Untitled";
        const eventTicker = ev.event_ticker || "";
        const seriesTicker = ev.series_ticker || eventTicker.split("-")[0] || "";
        const markets = ev.markets || [];

        if (markets.length === 0) continue;

        // Sum volume across all markets
        let totalVol = 0;
        for (const m of markets) {
          totalVol += getKalshiVolume(m);
        }

        if (totalVol < 1) continue;

        // Find highest-probability market
        let bestProb = 0;
        let bestOutcome = "Yes";

        for (const m of markets) {
          const prob = getKalshiProb(m);
          if (prob > bestProb) {
            bestProb = prob;
            if (markets.length > 1) {
              bestOutcome = m.subtitle || m.title || "Top";
              if (bestOutcome.length > 35)
                bestOutcome = bestOutcome.slice(0, 32) + "Ã¢â‚¬Â¦";
            }
          }
        }

        // Kalshi URL: use series ticker lowercased
        const kalshiUrl = `https://kalshi.com/markets/${seriesTicker.toLowerCase()}`;

        results.push({
          id: `kalshi-${eventTicker}`,
          title,
          probability: Math.round(bestProb * 10) / 10,
          topOutcome: bestOutcome,
          volume: totalVol,
          source: "kalshi",
          url: kalshiUrl,
          marketCount: markets.length,
        });
      } catch {
        continue;
      }
    }

    results.sort((a, b) => b.volume - a.volume);
    return results.slice(0, 15);
  } catch (err) {
    console.error("Kalshi fetch error:", err);
    return [];
  }
}

// Ã¢â€â‚¬Ã¢â€â‚¬ Components Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬

function MarketRow({ market, rank }: { market: Market; rank: number }) {
  const color = probColor(market.probability);
  const isPoly = market.source === "polymarket";

  return (
    <a
      href={market.url}
      target="_blank"
      rel="noopener noreferrer"
      className="block group"
    >
      <div className="flex items-start gap-3 px-3 py-3 hover:bg-zinc-800/60 transition-colors border-b border-zinc-800/50">
        {/* Rank */}
        <div className="text-zinc-500 text-xs mt-1 w-5 text-right shrink-0">
          {rank}
        </div>

        {/* Source Badge */}
        <div
          className={`shrink-0 mt-0.5 px-1.5 py-0.5 text-[10px] font-bold tracking-wider uppercase ${
            isPoly
              ? "bg-violet-500/20 text-violet-300 border border-violet-500/30"
              : "bg-blue-500/20 text-blue-300 border border-blue-500/30"
          }`}
        >
          {isPoly ? "POLY" : "KALSHI"}
        </div>

        {/* Content */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5">
            <span className="text-zinc-100 text-sm font-medium group-hover:underline truncate">
              {market.title}
            </span>
            <svg
              className="w-3 h-3 text-zinc-500 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
            >
              <path d="M18 13v6a2 2 0 01-2 2H5a2 2 0 01-2-2V8a2 2 0 012-2h6M15 3h6v6M10 14L21 3" />
            </svg>
          </div>

          <div className="flex items-center gap-3 mt-1.5">
            {/* Probability bar */}
            <div className="flex items-center gap-2 flex-1 min-w-0">
              <div
                className="h-1.5 flex-1 bg-zinc-800 overflow-hidden"
                style={{ maxWidth: 120 }}
              >
                <div
                  className="h-full transition-all duration-500"
                  style={{
                    width: `${Math.max(market.probability, 2)}%`,
                    backgroundColor: color,
                  }}
                />
              </div>
              <span
                className="text-xs font-bold shrink-0"
                style={{ color }}
              >
                {market.probability > 0 ? `${market.probability}%` : "Ã¢â‚¬â€"}
              </span>
            </div>

            {/* Top outcome label for multi-market events */}
            {market.marketCount > 1 && market.topOutcome !== "Yes" && (
              <span className="text-[10px] text-zinc-400 shrink-0 max-w-[120px] truncate" title={market.topOutcome}>
                {market.topOutcome}
              </span>
            )}

            {/* Volume */}
            <span className="text-xs text-zinc-500 shrink-0">
              {fmtVol(market.volume)}
            </span>

            {/* Market count */}
            {market.marketCount > 1 && (
              <span className="text-[10px] text-zinc-600 shrink-0">
                {market.marketCount}m
              </span>
            )}
          </div>
        </div>
      </div>
    </a>
  );
