type SourceFilter = "all" | "polymarket" | "kalshi";
type Status = "idle" | "loading" | "success" | "error";

export default function App() {
  const [swings, setSwings] = useState<MarketSwing[]>([]);
  const [filter, setFilter] = useState<SourceFilter>("all");
  const [pmStatus, setPmStatus] = useState<Status>("idle");
  const [kStatus, setKStatus] = useState<Status>("idle");
  const [pmError, setPmError] = useState("");
  const [kError, setKError] = useState("");
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const fetchData = useCallback(async () => {
    setPmStatus("loading");
    setKStatus("loading");

    const allSwings: MarketSwing[] = [];

    // Fetch both in parallel
    const [pmResult, kResult] = await Promise.allSettled([
      getPolymarketSwings(),
      getKalshiSwings(),
    ]);

    if (pmResult.status === "fulfilled") {
      allSwings.push(...pmResult.value);
      setPmStatus("success");
      setPmError("");
    } else {
      setPmStatus("error");
      setPmError(pmResult.reason?.message || "Failed");
    }

    if (kResult.status === "fulfilled") {
      allSwings.push(...kResult.value);
      setKStatus("success");
      setKError("");
    } else {
      setKStatus("error");
      setKError(kResult.reason?.message || "Failed");
    }

    // Sort by absolute change descending
    allSwings.sort((a, b) => b.absChange - a.absChange);
    setSwings(allSwings);
    setLastUpdated(new Date());
