import type { MarketSwing } from "../types";

const PROXY = "/api/proxy?url=";
function px(url: string): string {
  return PROXY + encodeURIComponent(url);
}

// ============================================================
// POLYMARKET — Using Events API for correct slugs
// ============================================================

interface GammaEvent {
  id: string;
  slug: string;        // ← this is the EVENT slug, used in polymarket.com/event/{slug}
  title: string;
  active: boolean;
  closed: boolean;
  volume24hr: number;
  markets: GammaMarket[];
}

interface GammaMarket {
  id: string;
  question: string;
  slug: string;
  outcomePrices: string;
  clobTokenIds: string;
  volume24hr: number;
  active: boolean;
}

interface PricePoint {
  t: number;
  p: number;
}

async function fetchGammaEvents(): Promise<GammaEvent[]> {
  const allEvents: GammaEvent[] = [];

  for (let offset = 0; offset < 200; offset += 100) {
    const url = `https://gamma-api.polymarket.com/events?active=true&closed=false&limit=100&offset=${offset}&order=volume24hr&ascending=false`;
    try {
      const res = await fetch(px(url));
      if (!res.ok) continue;
      const data = await res.json();
      if (Array.isArray(data)) {
        allEvents.push(...data);
      }
    } catch {
      // skip
    }
  }

  return allEvents;
}

async function fetchClobHistory(tokenId: string): Promise<PricePoint[]> {
  const url = `https://clob.polymarket.com/prices-history?market=${tokenId}&interval=1d&fidelity=60`;
  try {
    const res = await fetch(px(url));
    if (!res.ok) return [];
    const data = await res.json();
    return data?.history || [];
  } catch {
    return [];
  }
}

async function processBatch<T, R>(
  items: T[],
  batchSize: number,
  fn: (item: T) => Promise<R | null>
): Promise<(R | null)[]> {
  const results: (R | null)[] = [];
  for (let i = 0; i < items.length; i += batchSize) {
    const batch = items.slice(i, i + batchSize);
    const batchResults = await Promise.allSettled(batch.map(fn));
    for (const r of batchResults) {
      results.push(r.status === "fulfilled" ? r.value : null);
    }
  }
  return results;
}

export async function getPolymarketSwings(): Promise<MarketSwing[]> {
  const events = await fetchGammaEvents();
  if (!events.length) throw new Error("No events from Gamma API");

  // Flatten: for each event, take each market, pair it with the event slug for the URL
  const marketItems: { market: GammaMarket; eventSlug: string }[] = [];
  for (const event of events) {
    if (!event.markets || !Array.isArray(event.markets)) continue;
    for (const market of event.markets) {
      marketItems.push({ market, eventSlug: event.slug });
    }
  }

  // Take top 100 by volume
  marketItems.sort(
    (a, b) =>
      (parseFloat(String(b.market.volume24hr)) || 0) -
      (parseFloat(String(a.market.volume24hr)) || 0)
  );
  const topMarkets = marketItems.slice(0, 100);

  const processItem = async (item: {
    market: GammaMarket;
    eventSlug: string;
  }): Promise<MarketSwing | null> => {
    try {
      const { market, eventSlug } = item;

      let tokenIds: string[];
      try {
        tokenIds = JSON.parse(market.clobTokenIds || "[]");
      } catch {
        return null;
      }
      if (!tokenIds?.length) return null;

      let currentPrices: number[];
      try {
        currentPrices = JSON.parse(market.outcomePrices || "[]").map(Number);
      } catch {
        return null;
      }
      if (!currentPrices.length || isNaN(currentPrices[0])) return null;
      const currentPrice = currentPrices[0];

      const yesTokenId = tokenIds[0];
      const history = await fetchClobHistory(yesTokenId);
      if (history.length < 2) return null;

      const oldPrice = history[0].p;
      const newPrice = currentPrice;

      const change = (newPrice - oldPrice) * 100;
      const absChange = Math.abs(change);
      if (absChange < 0.5) return null;

      const vol =
        typeof market.volume24hr === "string"
          ? parseFloat(market.volume24hr)
          : market.volume24hr || 0;

      // Build URL using EVENT slug (not market slug)
      const url = eventSlug
        ? `https://polymarket.com/event/${eventSlug}`
        : `https://polymarket.com`;

      return {
        id: market.id,
        question: market.question,
        source: "polymarket",
        currentProb: newPrice * 100,
        previousProb: oldPrice * 100,
        change,
        absChange,
        volume24h: vol,
        url,
      };
    } catch {
      return null;
    }
  };

  const results = await processBatch(topMarkets, 15, processItem);
  return results.filter((r): r is MarketSwing => r !== null);
}

// ============================================================
// KALSHI — Public Markets API (no auth)
// ============================================================

interface KalshiMarket {
  ticker: string;
  event_ticker: string;
  title: string;
  subtitle: string;
  status: string;
  yes_bid_dollars: string;
  yes_ask_dollars: string;
  no_bid_dollars: string;
  no_ask_dollars: string;
  last_price_dollars: string;
  volume_24h_fp: string;
  volume_fp: string;
  previous_yes_bid_dollars: string;
  previous_yes_ask_dollars: string;
  open_interest_fp: string;
}

interface KalshiResponse {
  markets: KalshiMarket[];
  cursor: string;
}

async function fetchKalshiMarkets(): Promise<KalshiMarket[]> {
  const allMarkets: KalshiMarket[] = [];
  let cursor = "";
  const maxPages = 5;

  for (let page = 0; page < maxPages; page++) {
    const params = new URLSearchParams({ status: "open", limit: "1000" });
    if (cursor) params.set("cursor", cursor);

    const url = `https://api.elections.kalshi.com/trade-api/v2/markets?${params.toString()}`;
    try {
      const res = await fetch(px(url));
      if (!res.ok) {
        if (page === 0) throw new Error(`Kalshi API returned ${res.status}`);
        break;
      }
      const data: KalshiResponse = await res.json();
      if (data.markets?.length) {
        allMarkets.push(...data.markets);
      }
      cursor = data.cursor || "";
      if (!cursor) break;
    } catch (e) {
      if (page === 0) throw e;
      break;
    }
  }

  return allMarkets;
}

export async function getKalshiSwings(): Promise<MarketSwing[]> {
  const markets = await fetchKalshiMarkets();
  if (!markets.length) throw new Error("No markets from Kalshi API");

  const results: MarketSwing[] = [];

  for (const m of markets) {
    try {
      const yesBid = parseFloat(m.yes_bid_dollars || "0");
      const yesAsk = parseFloat(m.yes_ask_dollars || "0");
      const lastPrice = parseFloat(m.last_price_dollars || "0");
      const prevBid = parseFloat(m.previous_yes_bid_dollars || "0");
      const prevAsk = parseFloat(m.previous_yes_ask_dollars || "0");
      const vol24h = parseFloat(m.volume_24h_fp || "0");

      // Current price
      let currentPrice = 0;
      if (yesBid > 0 && yesAsk > 0) {
        currentPrice = (yesBid + yesAsk) / 2;
      } else if (yesAsk > 0) {
        currentPrice = yesAsk;
      } else if (yesBid > 0) {
        currentPrice = yesBid;
      } else if (lastPrice > 0) {
        currentPrice = lastPrice;
      }

      // Previous price
      let prevPrice = 0;
      if (prevBid > 0 && prevAsk > 0) {
        prevPrice = (prevBid + prevAsk) / 2;
      } else if (prevAsk > 0) {
        prevPrice = prevAsk;
      } else if (prevBid > 0) {
        prevPrice = prevBid;
      }

      if (currentPrice <= 0 || prevPrice <= 0) continue;
      if (currentPrice === prevPrice) continue;

      const change = (currentPrice - prevPrice) * 100;
      const absChange = Math.abs(change);
      if (absChange < 0.3) continue;

      let question = m.title || m.ticker;
      if (m.subtitle && m.subtitle !== question) {
        question += ` — ${m.subtitle}`;
      }

      // Kalshi URL: https://kalshi.com/markets/{event_ticker}
      const url = `https://kalshi.com/markets/${m.event_ticker}`;

      results.push({
        id: m.ticker,
        question,
        source: "kalshi",
        currentProb: currentPrice * 100,
        previousProb: prevPrice * 100,
        change,
        absChange,
        volume24h: vol24h,
        url,
      });
    } catch {
      continue;
    }
  }

  return results;
}

