      setError(err.message || 'Failed to fetch markets');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    load(true);

    if (intervalRef.current) clearInterval(intervalRef.current);
    intervalRef.current = setInterval(() => load(false), POLL_INTERVAL);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [load]);

  // Derive available categories from data
  const availableCategories = new Set(events.map(e => e.category));

  // Filter events
  const filtered = events.filter(e => {
    if (category !== 'all' && e.category !== category) return false;
    if (search) {
      const q = search.toLowerCase();
      return (
        e.title.toLowerCase().includes(q) ||
        e.event_ticker.toLowerCase().includes(q) ||
        e.series_ticker.toLowerCase().includes(q) ||
        e.featuredMarket.title.toLowerCase().includes(q)
      );
    }
    return true;
  });

  const totalVol24h = filtered.reduce((s, e) => s + e.totalVolume24h, 0);

  // Category tabs
  const knownCats = new Set(CATEGORIES as readonly string[]);
  const visibleCategories = CATEGORIES.filter(
    c => c === 'all' || availableCategories.has(c)
  );
  const hasOther = [...availableCategories].some(c => !knownCats.has(c));
  const allTabs = hasOther ? [...visibleCategories, 'other' as const] : visibleCategories;

  return (
    <div className="w-full h-full flex flex-col overflow-hidden">
      {/* Stats bar */}
      <div className="px-4 pt-3 pb-2 flex items-center justify-between text-[11px] text-zinc-500 border-b border-zinc-800/50">
        <div className="flex items-center gap-3">
          <span className="flex items-center gap-1">
            <TrendingUp className="w-3 h-3 text-emerald-400" />
            <span className="text-zinc-300">{filtered.length}</span>{' '}
            markets
          </span>
          {totalVol24h > 0 && (
            <span>
              24h Vol:{' '}
              <span className="text-zinc-300">
                {formatVolume(totalVol24h)}
              </span>
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {lastUpdate && (
            <span>
              Updated{' '}
              {lastUpdate.toLocaleTimeString([], {
                hour: '2-digit',
                minute: '2-digit',
              })}
            </span>
          )}
          <Button
            variant="ghost"
            size="icon"
            className="h-5 w-5"
            onClick={() => load(false)}
            disabled={refreshing}
          >
            <RefreshCw
              className={cn('w-3 h-3', refreshing && 'animate-spin')}
            />
          </Button>
        </div>
      </div>

      {/* Search */}
      <div className="px-4 pt-3 pb-2">
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-500" />
          <Input
            placeholder="Search markets..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-8 h-8 text-xs bg-zinc-900 border-zinc-800 text-zinc-100 placeholder:text-zinc-600 focus-visible:ring-zinc-700"
          />
        </div>
      </div>

      {/* Categories */}
      <div className="px-4 pb-2">
        <div className="flex gap-1 overflow-x-auto scrollbar-hide pb-1">
          {allTabs.map((cat) => {
            const info = CATEGORY_MAP[cat] || { label: cat.charAt(0).toUpperCase() + cat.slice(1), emoji: '📌' };
            return (
              <button
                key={cat}
                onClick={() => setCategory(cat)}
                className={cn(
                  'px-2.5 py-1 text-[11px] whitespace-nowrap transition-all shrink-0 border',
                  category === cat
                    ? 'bg-zinc-100 text-zinc-900 border-zinc-100 font-semibold'
                    : 'bg-zinc-900 text-zinc-400 border-zinc-800 hover:border-zinc-600 hover:text-zinc-300'
                )}
              >
                {info.emoji} {info.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="px-4 pb-2">
          <Alert variant="destructive" className="py-2">
            <AlertCircle className="w-3 h-3" />
            <AlertDescription className="text-xs">{error}</AlertDescription>
          </Alert>
        </div>
      )}

      {/* Content */}
      <ScrollArea className="flex-1 px-4">
        {loading ? (
          <div className="space-y-3 pb-4">
            {Array.from({ length: 8 }).map((_, i) => (
              <div key={i} className="bg-zinc-900 border border-zinc-800 p-3">
                <div className="flex gap-3">
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-3/4 bg-zinc-800" />
                    <Skeleton className="h-3 w-1/2 bg-zinc-800" />
                  </div>
                  <Skeleton className="w-12 h-8 bg-zinc-800" />
                </div>
                <Skeleton className="h-5 w-full mt-2 bg-zinc-800" />
