import { KalshiEvent, ProcessedEvent } from '../types';

const BASE_URL = 'https://api.elections.kalshi.com/trade-api/v2';

function parseDollarsToCents(dollars: string | undefined | null): number {
  if (!dollars) return 0;
  const val = parseFloat(dollars);
  if (isNaN(val)) return 0;
  return Math.round(val * 100);
}

function parseFP(fp: string | undefined | null): number {
  if (!fp) return 0;
  const val = parseFloat(fp);
  if (isNaN(val)) return 0;
  return val;
}

export function processEvent(event: KalshiEvent): ProcessedEvent | null {
  if (!event.markets || event.markets.length === 0) return null;

  let totalVolume = 0;
  let totalVolume24h = 0;
  let totalOI = 0;
  let bestMarket = event.markets[0];
  let bestVolume = 0;

  for (const m of event.markets) {
    const vol = parseFP(m.volume_fp) || (m.volume ?? 0);
    const vol24h = parseFP(m.volume_24h_fp) || (m.volume_24h ?? 0);
    const oi = parseFP(m.open_interest_fp) || (m.open_interest ?? 0);
    totalVolume += vol;
    totalVolume24h += vol24h;
    totalOI += oi;
    if (vol > bestVolume) {
      bestVolume = vol;
      bestMarket = m;
    }
  }

  const yesPrice = parseDollarsToCents(bestMarket.last_price_dollars) || 
                   parseDollarsToCents(bestMarket.yes_bid_dollars) || 
                   (bestMarket.yes_price ?? 0);

  const previousPrice = parseDollarsToCents(bestMarket.previous_yes_bid_dollars) || 
                        (bestMarket.previous_yes_bid ?? 0) ||
                        (bestMarket.previous_price ?? 0);

  return {
    event_ticker: event.event_ticker,
    series_ticker: event.series_ticker,
    title: event.title,
    sub_title: event.sub_title,
    category: (event.category || 'other').toLowerCase(),
    markets: event.markets,
    featuredMarket: bestMarket,
    totalVolume,
    totalVolume24h,
    totalOI,
    yesPrice,
    previousPrice,
  };
}

export async function fetchKalshiEvents(): Promise<{
  events: ProcessedEvent[];
  raw?: any;
  error?: string;
}> {
  const allEvents: ProcessedEvent[] = [];
  let cursor = '';
  let pages = 0;
  const maxPages = 5; // up to 500 events

  try {
    while (pages < maxPages) {
      const params = new URLSearchParams({
        status: 'open',
        with_nested_markets: 'true',
        limit: '100',
      });
      if (cursor) params.set('cursor', cursor);

      const url = `${BASE_URL}/events?${params.toString()}`;
      const proxyUrl = `/api/proxy?url=${encodeURIComponent(url)}`;

      const res = await fetch(proxyUrl);

      if (!res.ok) {
        const text = await res.text().catch(() => '');
        return {
          events: allEvents,
          error: `HTTP ${res.status}: ${text.slice(0, 200)}`,
        };
      }

      const data = await res.json();

      if (!data.events || !Array.isArray(data.events)) {
        return {
          events: allEvents,
          raw: data,
          error: `Unexpected response shape. Keys: ${Object.keys(data).join(', ')}`,
        };
      }

      for (const ev of data.events) {
        const processed = processEvent(ev);
        if (processed) {
          allEvents.push(processed);
        }
      }

      cursor = data.cursor || '';
      pages++;
      if (!cursor) break;
    }

    // Sort by 24h volume desc
    allEvents.sort((a, b) => b.totalVolume24h - a.totalVolume24h);

    return { events: allEvents };
  } catch (err: any) {
    return {
      events: [],
      error: `Fetch error: ${err.message}`,
    };
  }
}

export function formatVolume(vol: number): string {
  if (vol >= 1_000_000) return `$${(vol / 1_000_000).toFixed(1)}M`;
  if (vol >= 1_000) return `$${(vol / 1_000).toFixed(1)}K`;
  return `$${vol.toFixed(0)}`;
}

export function formatCount(vol: number): string {
  if (vol >= 1_000_000) return `${(vol / 1_000_000).toFixed(1)}M`;
  if (vol >= 1_000) return `${(vol / 1_000).toFixed(1)}K`;
  return `${vol.toFixed(0)}`;
}

export const CATEGORY_MAP: Record<string, { label: string; emoji: string }> = {
  all: { label: 'Trending', emoji: '🔥' },
  politics: { label: 'Politics', emoji: '🏛' },
  economics: { label: 'Economics', emoji: '📊' },
  finance: { label: 'Finance', emoji: '💰' },
  crypto: { label: 'Crypto', emoji: '₿' },
  sports: { label: 'Sports', emoji: '⚽' },
  climate: { label: 'Climate', emoji: '🌡' },
  tech: { label: 'Tech', emoji: '💻' },
  culture: { label: 'Culture', emoji: '🎭' },
  science: { label: 'Science', emoji: '🔬' },
  other: { label: 'Other', emoji: '📌' },
};

