import TraderRow from "./components/TraderRow";
import StatCard from "./components/StatCard";

const TIME_LABELS: Record<TimePeriod, string> = {
  "1d": "24H",
  "7d": "7D",
  "30d": "30D",
  all: "ALL",
};

export default function App() {
  const [platform, setPlatform] = useState<Platform>("polymarket");
  const [period, setPeriod] = useState<TimePeriod>("7d");
  const [sortBy, setSortBy] = useState<SortBy>("pnl");
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [lastUpdated, setLastUpdated] = useState(new Date());

  const dataSource = platform === "polymarket" ? polymarketTraders : kalshiTraders;

  const traders = useMemo(() => {
    const raw = dataSource[period] || [];
    const sorted = [...raw].sort((a, b) => {
      if (sortBy === "pnl") return b.pnl - a.pnl;
      return b.volume - a.volume;
    });
    return sorted.map((t, i) => ({ ...t, rank: i + 1 }));
  }, [platform, period, sortBy, dataSource]);

  const stats = useMemo(() => {
    if (!traders.length) return { topPnl: 0, totalVolume: 0, avgWinRate: 0, totalTraders: 0 };
