import { useState, useMemo, useCallback, useEffect } from "react";
import { AnimatePresence, motion } from "framer-motion";
import {
  TrendingUp,
  BarChart3,
  Users,
  Trophy,
  ArrowUpDown,
  RefreshCw,
  Clock,
  Activity,
} from "lucide-react";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { Platform, TimePeriod, SortBy, Trader } from "./types";
import { polymarketTraders, kalshiTraders, formatCurrency, formatVolume } from "./lib/data";
import TraderRow from "./components/TraderRow";
import StatCard from "./components/StatCard";

const TIME_LABELS: Record<TimePeriod, string> = {
  "1d": "24H",
  "7d": "7D",
  "30d": "30D",
  all: "ALL",
};

export default function App() {
  const [platform, setPlatform] = useState<Platform>("polymarket");
  const [period, setPeriod] = useState<TimePeriod>("7d");
  const [sortBy, setSortBy] = useState<SortBy>("pnl");
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [lastUpdated, setLastUpdated] = useState(new Date());

  const dataSource = platform === "polymarket" ? polymarketTraders : kalshiTraders;

  const traders = useMemo(() => {
    const raw = dataSource[period] || [];
    const sorted = [...raw].sort((a, b) => {
      if (sortBy === "pnl") return b.pnl - a.pnl;
      return b.volume - a.volume;
    });
    return sorted.map((t, i) => ({ ...t, rank: i + 1 }));
  }, [platform, period, sortBy, dataSource]);

  const stats = useMemo(() => {
    if (!traders.length) return { topPnl: 0, totalVolume: 0, avgWinRate: 0, totalTraders: 0 };
    const topPnl = traders[0]?.pnl || 0;
    const totalVolume = traders.reduce((s, t) => s + t.volume, 0);
    const avgWinRate = traders.reduce((s, t) => s + t.winRate, 0) / traders.length;
    return { topPnl, totalVolume, avgWinRate, totalTraders: traders.length };
  }, [traders]);

  const handleRefresh = useCallback(() => {
    setIsRefreshing(true);
    setTimeout(() => {
      setIsRefreshing(false);
      setLastUpdated(new Date());
    }, 800);
  }, []);

  // Auto-refresh every 60s
  useEffect(() => {
    const interval = setInterval(() => {
      setLastUpdated(new Date());
    }, 60000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="w-full h-full overflow-auto p-4 space-y-4">
      {/* Platform Tabs */}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div className="flex gap-1">
          <button
            onClick={() => setPlatform("polymarket")}
            className={cn(
              "px-4 py-2 text-sm font-semibold transition-all border",
              platform === "polymarket"
                ? "bg-violet-600/20 border-violet-500/50 text-violet-300"
                : "bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-700"
            )}
          >
            <span className="flex items-center gap-2">
              <div className="w-2 h-2 bg-violet-500" />
              Polymarket
            </span>
          </button>
          <button
            onClick={() => setPlatform("kalshi")}
            className={cn(
              "px-4 py-2 text-sm font-semibold transition-all border",
              platform === "kalshi"
                ? "bg-blue-600/20 border-blue-500/50 text-blue-300"
                : "bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-700"
            )}
          >
            <span className="flex items-center gap-2">
              <div className="w-2 h-2 bg-blue-500" />
              Kalshi
            </span>
          </button>
        </div>

        <div className="flex items-center gap-2">
          <span className="text-[11px] text-zinc-600 font-mono">
            {lastUpdated.toLocaleTimeString()}
          </span>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleRefresh}
            className="h-7 w-7 p-0 text-zinc-500 hover:text-zinc-300"
          >
            <RefreshCw size={14} className={cn(isRefreshing && "animate-spin")} />
          </Button>
        </div>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-2">
        <StatCard
          label="Top P&L"
          value={(stats.topPnl >= 0 ? "+" : "") + formatCurrency(stats.topPnl)}
          icon={<Trophy size={16} />}
          accent="text-emerald-400"
        />
        <StatCard
          label="Total Volume"
          value={formatVolume(stats.totalVolume)}
          icon={<BarChart3 size={16} />}
        />
        <StatCard
          label="Avg Win Rate"
          value={`${stats.avgWinRate.toFixed(1)}%`}
          icon={<Activity size={16} />}
          accent="text-yellow-400"
        />
        <StatCard
          label="Traders"
          value={stats.totalTraders.toString()}
          icon={<Users size={16} />}
        />
      </div>

      {/* Controls */}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        {/* Time Period */}
        <div className="flex gap-1">
          {(Object.keys(TIME_LABELS) as TimePeriod[]).map((p) => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={cn(
                "px-3 py-1.5 text-xs font-semibold transition-all border",
                period === p
                  ? platform === "polymarket"
                    ? "bg-violet-600/20 border-violet-500/40 text-violet-300"
                    : "bg-blue-600/20 border-blue-500/40 text-blue-300"
                  : "bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:text-zinc-300"
              )}
            >
              {TIME_LABELS[p]}
            </button>
          ))}
        </div>

        {/* Sort */}
        <div className="flex items-center gap-1">
          <span className="text-[11px] text-zinc-600 mr-1">SORT:</span>
          <button
            onClick={() => setSortBy("pnl")}
            className={cn(
              "px-3 py-1.5 text-xs font-semibold transition-all border flex items-center gap-1",
              sortBy === "pnl"
                ? "bg-emerald-600/20 border-emerald-500/40 text-emerald-300"
                : "bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:text-zinc-300"
            )}
          >
            <TrendingUp size={12} />
            P&L
          </button>
          <button
            onClick={() => setSortBy("volume")}
            className={cn(
              "px-3 py-1.5 text-xs font-semibold transition-all border flex items-center gap-1",
              sortBy === "volume"
                ? "bg-emerald-600/20 border-emerald-500/40 text-emerald-300"
                : "bg-zinc-900/40 border-zinc-800 text-zinc-500 hover:text-zinc-300"
            )}
          >
            <BarChart3 size={12} />
            Volume
          </button>
        </div>
      </div>

      {/* Leaderboard Table */}
      <div className="border border-zinc-800 bg-zinc-900/30">
        <table className="w-full">
          <thead>
            <tr className="border-b border-zinc-800 text-[11px] uppercase tracking-wider text-zinc-500">
              <th className="py-2 px-2 text-left w-10">#</th>
              <th className="py-2 px-2 text-left">Trader</th>
              <th className="py-2 px-2 text-right">
                <span className="flex items-center justify-end gap-1">
                  P&L
                  {sortBy === "pnl" && <ArrowUpDown size={10} className="text-emerald-400" />}
                </span>
              </th>
              <th className="py-2 px-2 text-right">
                <span className="flex items-center justify-end gap-1">
                  Volume
                  {sortBy === "volume" && <ArrowUpDown size={10} className="text-emerald-400" />}
                </span>
              </th>
              <th className="py-2 px-2 text-right hidden sm:table-cell">Markets</th>
              <th className="py-2 px-2 text-right hidden sm:table-cell">Win%</th>
              <th className="py-2 px-2 text-right hidden md:table-cell">Positions</th>
            </tr>
          </thead>
          <tbody>
            <AnimatePresence mode="popLayout">
              {traders.map((trader, idx) => (
                <TraderRow
                  key={`${platform}-${period}-${trader.name}`}
                  trader={trader}
                  index={idx}
                  platform={platform}
                />
              ))}
            </AnimatePresence>
          </tbody>
        </table>
      </div>

      {/* Footer */}
      <div className="flex items-center justify-between text-[11px] text-zinc-600">
        <div className="flex items-center gap-1.5">
          <Clock size={10} />
          <span>Data refreshed periodically · Rankings based on {sortBy === "pnl" ? "profit/loss" : "trading volume"}</span>
        </div>
        <Badge variant="outline" className="text-[10px] border-zinc-800 text-zinc-600 px-2 py-0">
          {platform === "polymarket" ? "Polygon" : "CFTC Regulated"}
        </Badge>
      </div>
    </div>
  );
}

