import { useState, useEffect, useCallback, useMemo } from 'react';
import { RefreshCw, Search, AlertCircle, Newspaper, Rss } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';

import { NewsItem, CategoryKey } from './types';
import { fetchNews, FEEDS } from './lib/api';
import NewsRow from './components/NewsRow';

export default function App() {
  const [items, setItems] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [category, setCategory] = useState<CategoryKey>('all');
  const [search, setSearch] = useState('');
  const [feedResults, setFeedResults] = useState<Record<string, number>>({});

  const loadData = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    else setLoading(true);
    setError(null);

    try {
      const data = await fetchNews();
      setItems(data.items);
      setFeedResults(data.feedResults);
      setLastUpdated(new Date());

      if (data.items.length === 0) {
        setError('No news items retrieved. Feeds may be temporarily unavailable.');
      }
    } catch (e: any) {
      setError(e.message || 'Failed to load news');
      console.error('News fetch error:', e);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    const interval = setInterval(() => loadData(true), 300_000);
    return () => clearInterval(interval);
  }, [loadData]);

  const filtered = useMemo(() => {
    let result = items;

    if (category !== 'all') {
      result = result.filter((item) => item.category === category);
    }

    if (search.trim()) {
      const q = search.toLowerCase().trim();
      result = result.filter(
        (item) =>
          item.title.toLowerCase().includes(q) ||
          item.source.toLowerCase().includes(q)
      );
    }

    return result;
  }, [items, category, search]);

  const categoryCounts = useMemo(() => {
    const counts: Record<string, number> = { all: items.length };
    for (const item of items) {
      counts[item.category] = (counts[item.category] || 0) + 1;
    }
    return counts;
  }, [items]);

  const activeFeedCount = Object.values(feedResults).filter((v) => v >= 0).length;
  const failedFeedCount = Object.values(feedResults).filter((v) => v === -1).length;

  return (
    <div className="w-full h-full overflow-hidden flex flex-col bg-zinc-950">
      {/* Header */}
      <div className="flex-shrink-0 px-3 pt-2.5 pb-1.5 space-y-1.5">
        {/* Status bar */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Rss size={11} className="text-amber-400" />
            <span className="text-[10px] text-zinc-500 uppercase tracking-wider">
              Live Ã¢â‚¬Â¢ {items.length} stories
              {failedFeedCount > 0 && (
                <span className="text-amber-500 ml-1">
                  Ã¢â‚¬Â¢ {failedFeedCount} feed{failedFeedCount > 1 ? 's' : ''} down
                </span>
              )}
            </span>
          </div>
          <div className="flex items-center gap-2">
            {lastUpdated && (
              <span className="text-[10px] text-zinc-600">
                {formatDistanceToNow(lastUpdated, { addSuffix: true })}
              </span>
            )}
            <button
              onClick={() => loadData(true)}
              disabled={refreshing}
              className="p-1 text-zinc-500 hover:text-zinc-300 transition-colors disabled:opacity-50"
              title="Refresh"
            >
              <RefreshCw size={11} className={refreshing ? 'animate-spin' : ''} />
            </button>
          </div>
        </div>

        {/* Search */}
        <div className="relative">
          <Search
            size={11}
            className="absolute left-2 top-1/2 -translate-y-1/2 text-zinc-500 pointer-events-none"
          />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Filter headlines..."
            className="w-full bg-zinc-900 border border-zinc-800 text-zinc-200 text-[11px] pl-6 pr-7 py-1 placeholder:text-zinc-600 focus:outline-none focus:border-zinc-600 transition-colors"
          />
          {search && (
            <button
              onClick={() => setSearch('')}
              className="absolute right-2 top-1/2 -translate-y-1/2 text-zinc-500 hover:text-zinc-300 text-[10px] leading-none"
            >
              Ã¢Å“â€¢
            </button>
          )}
        </div>

        {/* Category filter */}
        <div className="flex flex-wrap gap-1">
          <button
            onClick={() => setCategory('all')}
            className={`px-1.5 py-px text-[10px] font-semibold uppercase tracking-wider border transition-colors ${
              category === 'all'
                ? 'border-zinc-600 text-zinc-200 bg-zinc-800'
                : 'border-zinc-800/50 text-zinc-600 hover:text-zinc-400 hover:border-zinc-700'
            }`}
          >
            All ({categoryCounts.all || 0})
          </button>
          {FEEDS.map((feed) => (
            <button
              key={feed.category}
              onClick={() => setCategory(feed.category)}
              className={`px-1.5 py-px text-[10px] font-semibold uppercase tracking-wider border transition-colors ${
                category === feed.category
                  ? `${feed.color.border} ${feed.color.text} ${feed.color.bg}`
                  : 'border-zinc-800/50 text-zinc-600 hover:text-zinc-400 hover:border-zinc-700'
              }`}
            >
              {feed.label} ({categoryCounts[feed.category] || 0})
            </button>
          ))}
        </div>
      </div>

      {/* Error */}
      {error && !loading && (
        <div className="mx-3 mb-1.5 flex items-center gap-2 bg-red-500/10 border border-red-500/30 px-2.5 py-1.5">
          <AlertCircle size={11} className="text-red-400 shrink-0" />
          <span className="text-[11px] text-red-400">{error}</span>
        </div>
      )}

      {/* Content */}
      <div className="flex-1 min-h-0">
        {loading ? (
          <div className="px-3 pt-1">
            {Array.from({ length: 12 }).map((_, i) => (
              <div
                key={i}
                className="flex items-start gap-2.5 py-2 border-b border-zinc-800/50"
              >
                <Skeleton className="h-3.5 w-12 shrink-0 mt-0.5" />
                <div className="flex-1 space-y-1">
                  <Skeleton className="h-3 w-full" />
                  <Skeleton className="h-3 w-3/4" />
                  <Skeleton className="h-2.5 w-1/4" />
                </div>
              </div>
            ))}
          </div>
        ) : (
          <ScrollArea className="h-full">
            {filtered.length > 0 ? (
              <div>
                {filtered.map((item) => (
                  <NewsRow key={item.id} item={item} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-zinc-500">
                <Newspaper size={18} className="mb-2 text-zinc-600" />
                <span className="text-[11px]">
                  {search
                    ? `No results for "${search}"`
                    : 'No news items found'}
                </span>
                {search && (
                  <button
                    onClick={() => setSearch('')}
                    className="mt-1.5 text-[10px] text-zinc-400 hover:text-zinc-200 underline"
                  >
                    Clear search
                  </button>
                )}
              </div>
            )}
          </ScrollArea>
        )}
      </div>

      {/* Footer */}
      <div className="flex-shrink-0 px-3 py-1 border-t border-zinc-800/60 flex items-center justify-between">
        <div className="flex items-center gap-1.5">
          {FEEDS.map((feed) => (
            <div
              key={feed.category}
              className={`w-1.5 h-1.5 ${
                feedResults[feed.category] === -1
                  ? 'bg-red-500'
                  : (feedResults[feed.category] || 0) > 0
                  ? feed.dotColor
                  : 'bg-zinc-700'
              }`}
              title={`${feed.label}: ${
                feedResults[feed.category] === -1
                  ? 'Failed'
                  : `${feedResults[feed.category] || 0} items`
              }`}
            />
          ))}
          <span className="text-[10px] text-zinc-600 ml-0.5">
            {activeFeedCount}/{FEEDS.length} feeds
          </span>
        </div>
        <span className="text-[10px] text-zinc-600">
          {filtered.length} headline{filtered.length !== 1 ? 's' : ''} Ã¢â‚¬Â¢ Auto-refresh 5m
        </span>
      </div>
    </div>
  );
}

