}

export type CategoryKey = 'all' | 'world' | 'politics' | 'business' | 'tech' | 'sports' | 'science';

export interface FeedConfig {
  category: Exclude<CategoryKey, 'all'>;
  label: string;
  url: string;
  color: { bg: string; text: string; border: string };
  dotColor: string;
}

