import { NewsItem, FeedConfig, CategoryKey } from '../types';

export const FEEDS: FeedConfig[] = [
  {
    category: 'politics',
    label: 'Politics',
    url: 'https://news.google.com/rss/headlines/section/topic/NATION?hl=en-US&gl=US&ceid=US:en',
    color: { bg: 'bg-red-500/15', text: 'text-red-400', border: 'border-red-500/30' },
    dotColor: 'bg-red-500',
  },
  {
    category: 'world',
    label: 'World',
    url: 'https://news.google.com/rss/headlines/section/topic/WORLD?hl=en-US&gl=US&ceid=US:en',
    color: { bg: 'bg-blue-500/15', text: 'text-blue-400', border: 'border-blue-500/30' },
    dotColor: 'bg-blue-500',
  },
  {
    category: 'business',
    label: 'Business',
    url: 'https://news.google.com/rss/headlines/section/topic/BUSINESS?hl=en-US&gl=US&ceid=US:en',
    color: { bg: 'bg-green-500/15', text: 'text-green-400', border: 'border-green-500/30' },
    dotColor: 'bg-green-500',
  },
  {
    category: 'tech',
    label: 'Tech',
    url: 'https://news.google.com/rss/headlines/section/topic/TECHNOLOGY?hl=en-US&gl=US&ceid=US:en',
    color: { bg: 'bg-purple-500/15', text: 'text-purple-400', border: 'border-purple-500/30' },
    dotColor: 'bg-purple-500',
  },
  {
    category: 'science',
    label: 'Science',
    url: 'https://news.google.com/rss/headlines/section/topic/SCIENCE?hl=en-US&gl=US&ceid=US:en',
    color: { bg: 'bg-cyan-500/15', text: 'text-cyan-400', border: 'border-cyan-500/30' },
    dotColor: 'bg-cyan-500',
  },
  {
    category: 'sports',
    label: 'Sports',
    url: 'https://news.google.com/rss/headlines/section/topic/SPORTS?hl=en-US&gl=US&ceid=US:en',
    color: { bg: 'bg-orange-500/15', text: 'text-orange-400', border: 'border-orange-500/30' },
    dotColor: 'bg-orange-500',
  },
];

function decodeHTMLEntities(text: string): string {
  const textarea = document.createElement('textarea');
  textarea.innerHTML = text;
  return textarea.value;
}

function parseTitle(rawTitle: string): { title: string; extractedSource: string } {
  const decoded = decodeHTMLEntities(rawTitle);
  // Google News format: "Headline - Source Name"
  const match = decoded.match(/^(.+)\s+-\s+([^-]+)$/);
  if (match) {
    return { title: match[1].trim(), extractedSource: match[2].trim() };
  }
  return { title: decoded, extractedSource: '' };
}

function parseRSS(xml: string, category: Exclude<CategoryKey, 'all'>): NewsItem[] {
  const parser = new DOMParser();
  const doc = parser.parseFromString(xml, 'text/xml');

  const parseError = doc.querySelector('parsererror');
  if (parseError) {
    console.warn(`RSS parse error for ${category}:`, parseError.textContent);
    return [];
  }

  const items = doc.querySelectorAll('item');
  const results: NewsItem[] = [];

  items.forEach((item, i) => {
    const rawTitle = item.querySelector('title')?.textContent?.trim() || '';
    const link = item.querySelector('link')?.textContent?.trim() || '';
    const pubDateStr = item.querySelector('pubDate')?.textContent?.trim() || '';
    const sourceEl = item.querySelector('source')?.textContent?.trim() || '';

    if (!rawTitle) return;

    const { title, extractedSource } = parseTitle(rawTitle);
    const source = sourceEl || extractedSource || 'Unknown';
    const pubDate = pubDateStr ? new Date(pubDateStr) : new Date();

    // Skip items with invalid dates
    if (isNaN(pubDate.getTime())) return;

    results.push({
      id: `${category}-${i}-${pubDate.getTime()}`,
      title,
      link,
      source,
      pubDate,
      category,
    });
  });

  return results;
}

export async function fetchNews(): Promise<{
  items: NewsItem[];
  feedResults: Record<string, number>;
}> {
  const feedResults: Record<string, number> = {};

  const results = await Promise.allSettled(
    FEEDS.map(async (feed) => {
      const proxyUrl =
        '/api/proxy?url=' + encodeURIComponent(feed.url);
      const res = await fetch(proxyUrl);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const text = await res.text();
      const items = parseRSS(text, feed.category);
      feedResults[feed.category] = items.length;
      return items;
    })
  );

  const allItems: NewsItem[] = [];
  for (let i = 0; i < results.length; i++) {
    const result = results[i];
    if (result.status === 'fulfilled') {
      allItems.push(...result.value);
    } else {
      feedResults[FEEDS[i].category] = -1; // mark as failed
      console.warn(`Feed ${FEEDS[i].category} failed:`, result.reason);
    }
  }

  // Sort by date, newest first
  allItems.sort((a, b) => b.pubDate.getTime() - a.pubDate.getTime());

  // Deduplicate by normalized title prefix
  const seen = new Set<string>();
  const unique = allItems.filter((item) => {
    const key = item.title
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, '')
      .trim()
      .slice(0, 60);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

  return { items: unique, feedResults };
}

export function getCategoryConfig(
  category: Exclude<CategoryKey, 'all'>
): FeedConfig | undefined {
  return FEEDS.find((f) => f.category === category);
}

