import { Trade } from '../types';
import { TrendingUp, TrendingDown } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { formatDistanceToNow } from 'date-fns';

function formatDollar(n: number): string {
  if (n >= 1_000_000) return `$${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `$${(n / 1_000).toFixed(1)}K`;
  return `$${n.toFixed(0)}`;
}

function formatContracts(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n.toFixed(0);
}

export default function TradeRow({ trade }: { trade: Trade }) {
  const isYes = trade.side === 'yes';
  const timeAgo = formatDistanceToNow(new Date(trade.timestamp), { addSuffix: true });

  return (
    <div className="flex items-start gap-3 px-3 py-2.5 border-b border-zinc-800/60 hover:bg-zinc-800/30 transition-colors group">
      {/* Platform badge */}
      <div className="flex-shrink-0 mt-0.5">
        <Badge
          variant="outline"
          className={`text-[10px] font-bold tracking-wider px-1.5 py-0 border ${
            trade.platform === 'kalshi'
              ? 'border-blue-500/40 text-blue-400 bg-blue-500/10'
              : 'border-purple-500/40 text-purple-400 bg-purple-500/10'
          }`}
        >
          {trade.platform === 'kalshi' ? 'KAL' : 'PLY'}
        </Badge>
      </div>

      {/* Main content */}
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-0.5">
          <span className="text-zinc-200 text-xs font-medium truncate leading-tight">
            {trade.market}
          </span>
        </div>
        <div className="flex items-center gap-2 text-[11px]">
          <span className={`inline-flex items-center gap-0.5 font-semibold ${
            isYes ? 'text-emerald-400' : 'text-red-400'
          }`}>
            {isYes ? <TrendingUp size={10} /> : <TrendingDown size={10} />}
            {isYes ? 'YES' : 'NO'}
          </span>
          <span className="text-zinc-500">@</span>
          <span className="text-zinc-300 font-mono">
            {(trade.price * 100).toFixed(0)}¢
          </span>
          <span className="text-zinc-600">·</span>
          <span className="text-zinc-400 font-mono">
            {formatContracts(trade.contracts)} contracts
          </span>
        </div>
      </div>

      {/* Amount + time */}
      <div className="flex-shrink-0 text-right">
        <div className={`text-xs font-bold font-mono ${
          trade.size >= 50000 ? 'text-amber-400' : 'text-zinc-200'
        }`}>
          {formatDollar(trade.size)}
        </div>
        <div className="text-[10px] text-zinc-500 mt-0.5">
          {timeAgo}
        </div>
      </div>
    </div>
  );
}

