import { Trade, MarketActivity } from '../types';
import { Activity, DollarSign, Flame, BarChart3 } from 'lucide-react';

function formatDollar(n: number): string {
  if (n >= 1_000_000) return `$${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `$${(n / 1_000).toFixed(1)}K`;
  return `$${n.toFixed(0)}`;
}

interface Props {
  trades: Trade[];
  markets: MarketActivity[];
}

export default function SummaryBar({ trades, markets }: Props) {
  const totalTradeVol = trades.reduce((s, t) => s + t.size, 0);
  const total24hVol = markets.reduce((s, m) => s + m.volume24h, 0);
  const biggestTrade = trades[0];
  const biggestMove = [...markets].sort(
    (a, b) => Math.abs(b.priceChange24h) - Math.abs(a.priceChange24h)
  )[0];

  const stats = [
    {
      icon: DollarSign,
      label: 'Large Bets',
      value: formatDollar(totalTradeVol),
      color: 'text-emerald-400',
    },
    {
      icon: BarChart3,
      label: '24h Volume',
      value: formatDollar(total24hVol),
      color: 'text-blue-400',
    },
    {
      icon: Flame,
      label: 'Biggest Bet',
      value: biggestTrade ? formatDollar(biggestTrade.size) : '—',
      color: 'text-amber-400',
    },
    {
      icon: Activity,
      label: 'Top Move',
      value: biggestMove
        ? `${biggestMove.priceChange24h >= 0 ? '+' : ''}${(biggestMove.priceChange24h * 100).toFixed(1)}¢`
        : '—',
      color: biggestMove && biggestMove.priceChange24h >= 0 ? 'text-emerald-400' : 'text-red-400',
    },
  ];

  return (
    <div className="grid grid-cols-4 gap-2">
      {stats.map((s) => (
        <div
          key={s.label}
          className="flex flex-col items-center justify-center bg-zinc-900/80 border border-zinc-800 px-2 py-2"
        >
          <s.icon size={13} className={`${s.color} mb-1`} />
          <span className={`text-sm font-bold font-mono ${s.color}`}>
            {s.value}
          </span>
          <span className="text-[10px] text-zinc-500 uppercase tracking-wider">
            {s.label}
          </span>
        </div>
      ))}
    </div>
  );
}

