                  <AlertCircle size={20} className="mb-2" />
                  <span className="text-xs">No notable movers found</span>
                </div>
              )
            )}
          </ScrollArea>
        )}
      </div>

      {/* Footer */}
      <div className="flex-shrink-0 px-3 py-1.5 border-t border-zinc-800/60 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1">
            <div className="w-1.5 h-1.5 bg-blue-400 rounded-full" />
            <span className="text-[10px] text-zinc-500">Kalshi ({kalshiCount})</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-1.5 h-1.5 bg-purple-400 rounded-full" />
            <span className="text-[10px] text-zinc-500">Polymarket ({polyCount})</span>
          </div>
        </div>
        <span className="text-[10px] text-zinc-600">
          Sorted by size • Auto-refresh 60s
        </span>
      </div>
    </div>
  );
}

