        <div className="flex items-center gap-3 text-zinc-500">
          <span>Match: <span className="text-zinc-400">{(matchScore * 100).toFixed(0)}%</span></span>
          <span>Spread: <span className="text-zinc-400">{(spread * 100).toFixed(1)}¢</span></span>
