        </div>

        {hasArb ? (
          <div className="flex items-center gap-1.5">
            <Zap className="w-3 h-3 text-emerald-400" />
            <span className="text-emerald-400 font-bold tabular-nums">
              +{(strat.profit * 100).toFixed(1)}¢
            </span>
            <span className="text-emerald-500/70 tabular-nums">
              ({strat.profitPct.toFixed(1)}%)
            </span>
          </div>
        ) : (
          <span className="text-zinc-600">No arb</span>
        )}
      </div>

      {/* Strategy callout for arbs */}
      {hasArb && (
        <div className="border-t border-emerald-500/20 px-3 py-1.5 flex items-center gap-2 text-[10px] bg-emerald-500/5">
          <span className="text-emerald-400">▶</span>
          <span className="text-zinc-400">
            Buy <span className="text-emerald-300">{strat.polyAction}</span> on Poly at {cents(strat.polyCost)} + Buy <span className="text-emerald-300">{strat.kalshiAction}</span> on Kalshi at {cents(strat.kalshiCost)} = {cents(strat.totalCost)} → <span className="text-emerald-300 font-bold">+{cents(strat.profit)}</span>
          </span>
        </div>
      )}
    </div>
  );
}

