import { useState, useEffect, useCallback, useRef } from 'react';
import { RefreshCw, AlertCircle, Search, Zap, Activity, Filter, ChevronDown, ChevronUp } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { AnimatePresence, motion } from 'framer-motion';
import { cn } from '@/lib/utils';
import { ArbitrageOpportunity } from './types';
import { scanArbitrage, ScanResult } from './lib/api';
import ArbCard from './components/ArbCard';

const POLL_INTERVAL = 60_000;

type FilterMode = 'all' | 'arb' | 'spread';

function App() {
  const [opportunities, setOpportunities] = useState<ArbitrageOpportunity[]>([]);
  const [polyCount, setPolyCount] = useState(0);
  const [kalshiCount, setKalshiCount] = useState(0);
  const [matchCount, setMatchCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdate, setLastUpdate] = useState<Date | null>(null);
  const [search, setSearch] = useState('');
  const [filterMode, setFilterMode] = useState<FilterMode>('all');
  const [countdown, setCountdown] = useState(60);
  const [debugOpen, setDebugOpen] = useState(false);
  const [debugData, setDebugData] = useState<{ polySamples: string[]; kalshiSamples: string[] } | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const load = useCallback(async (initial = false) => {
    try {
      if (initial) setLoading(true);
      else setRefreshing(true);
      setError(null);

      const result = await scanArbitrage();

      setOpportunities(result.opportunities);
      setPolyCount(result.polyCount);
      setKalshiCount(result.kalshiCount);
      setMatchCount(result.matchCount);
      setLastUpdate(new Date());
      setCountdown(60);
      setDebugData({ polySamples: result.polySamples, kalshiSamples: result.kalshiSamples });

      if (result.error) setError(result.error);
    } catch (err: any) {
      setError(err.message || 'Scan failed');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    load(true);
    intervalRef.current = setInterval(() => load(false), POLL_INTERVAL);
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [load]);

  useEffect(() => {
    const t = setInterval(() => setCountdown(c => Math.max(0, c - 1)), 1000);
    return () => clearInterval(t);
  }, []);

  const arbCount = opportunities.filter(o => o.hasArb).length;
  const highSpread = opportunities.filter(o => o.spread >= 0.03).length;

  const filtered = opportunities.filter(o => {
    if (filterMode === 'arb' && !o.hasArb) return false;
    if (filterMode === 'spread' && o.spread < 0.03) return false;
    if (search.trim()) {
      const q = search.toLowerCase();
      return o.polyMarket.title.toLowerCase().includes(q) ||
             o.kalshiMarket.title.toLowerCase().includes(q);
    }
    return true;
  });

  return (
    <div className="w-full h-full flex flex-col overflow-hidden">
      {/* Top bar */}
      <div className="px-3 pt-2.5 pb-2 border-b border-zinc-800/60 space-y-2">
        {/* Stats row */}
        <div className="flex items-center justify-between text-[11px]">
          <div className="flex items-center gap-3 text-zinc-500 flex-wrap">
            {arbCount > 0 && (
              <span className="flex items-center gap-1 text-emerald-400">
                <Zap className="w-3 h-3" />
                <span className="font-bold">{arbCount}</span> arb{arbCount !== 1 && 's'}
              </span>
            )}
            <span className="flex items-center gap-1">
              <Activity className="w-3 h-3" />
              <span className="text-zinc-300">{matchCount}</span> matched
            </span>
            <span className="text-zinc-600">
              {polyCount}P · {kalshiCount}K
            </span>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <span className="text-zinc-600 tabular-nums text-[10px]">{countdown}s</span>
            {lastUpdate && (
              <span className="text-zinc-600 text-[10px] hidden sm:inline">
                {lastUpdate.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            )}
            <Button variant="ghost" size="icon" className="h-5 w-5"
              onClick={() => load(false)} disabled={refreshing || loading}>
              <RefreshCw className={cn('w-3 h-3', (refreshing || loading) && 'animate-spin')} />
            </Button>
          </div>
        </div>

        {/* Search */}
        <div className="relative">
          <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-zinc-600" />
          <Input
            placeholder="Filter markets..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-7 h-7 text-[11px] bg-zinc-900 border-zinc-800 text-zinc-200 placeholder:text-zinc-600"
          />
        </div>

        {/* Filter pills */}
        <div className="flex gap-1">
          {([
            { key: 'all' as const, label: 'All', count: opportunities.length },
            { key: 'arb' as const, label: '⚡ Arb', count: arbCount },
            { key: 'spread' as const, label: '↔ Spread ≥3¢', count: highSpread },
          ]).map(f => (
            <button key={f.key} onClick={() => setFilterMode(f.key)}
              className={cn(
                'px-2 py-0.5 text-[10px] border transition-colors flex items-center gap-1',
                filterMode === f.key
                  ? 'bg-zinc-200 text-zinc-900 border-zinc-200 font-semibold'
                  : 'bg-zinc-900 text-zinc-500 border-zinc-800 hover:border-zinc-600'
              )}>
              {f.label}
              <span className="text-[9px] opacity-60">{f.count}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="px-3 pt-2">
          <Alert variant="destructive" className="py-1.5">
            <AlertCircle className="w-3 h-3" />
            <AlertDescription className="text-[11px]">{error}</AlertDescription>
          </Alert>
        </div>
      )}

      {/* Main content */}
      <ScrollArea className="flex-1">
        <div className="px-3 py-2">
          {loading ? (
            <div className="space-y-2">
              {Array.from({ length: 5 }).map((_, i) => (
                <div key={i} className="border border-zinc-800 bg-zinc-900/60 p-3 space-y-2">
                  <Skeleton className="h-3 w-3/4 bg-zinc-800" />
                  <Skeleton className="h-3 w-2/3 bg-zinc-800" />
                  <div className="grid grid-cols-3 gap-2">
                    <Skeleton className="h-8 bg-zinc-800" />
                    <Skeleton className="h-8 bg-zinc-800" />
                    <Skeleton className="h-8 bg-zinc-800" />
                  </div>
                </div>
              ))}
            </div>
          ) : filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-10 text-zinc-500">
              {matchCount === 0 && !search ? (
                <>
                  <Activity className="w-8 h-8 mb-3 text-zinc-600" />
                  <p className="text-xs mb-1">No matching markets found</p>
                  <p className="text-[10px] text-zinc-600 text-center max-w-xs">
                    Scanned {polyCount} Polymarket + {kalshiCount} Kalshi markets.
                    {polyCount === 0 && kalshiCount === 0
                      ? ' Both APIs may be unreachable.'
                      : polyCount === 0
                        ? ' Polymarket API failed.'
                        : kalshiCount === 0
                          ? ' Kalshi API failed.'
                          : ' No overlapping markets detected.'}
                  </p>

                  {/* Debug panel */}
                  {debugData && (
                    <div className="mt-3 w-full max-w-sm">
                      <button onClick={() => setDebugOpen(!debugOpen)}
                        className="text-[10px] text-zinc-600 hover:text-zinc-400 flex items-center gap-1 mx-auto">
                        Debug info {debugOpen ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                      </button>
                      {debugOpen && (
                        <div className="mt-2 p-2 bg-zinc-950 border border-zinc-800 text-[9px] text-zinc-500 space-y-2">
                          <div>
                            <span className="text-zinc-400">Polymarket samples ({polyCount}):</span>
                            {debugData.polySamples.length > 0
                              ? debugData.polySamples.map((s, i) => <div key={i} className="truncate pl-2">• {s}</div>)
                              : <div className="pl-2 text-zinc-600">None fetched</div>}
                          </div>
                          <div>
                            <span className="text-zinc-400">Kalshi samples ({kalshiCount}):</span>
                            {debugData.kalshiSamples.length > 0
                              ? debugData.kalshiSamples.map((s, i) => <div key={i} className="truncate pl-2">• {s}</div>)
                              : <div className="pl-2 text-zinc-600">None fetched</div>}
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                </>
              ) : (
                <>
                  <Filter className="w-6 h-6 mb-2 text-zinc-600" />
                  <p className="text-xs">No results</p>
                  <p className="text-[10px] text-zinc-600">
                    {search ? 'Try a different search' : 'Change the filter'}
                  </p>
                </>
              )}
            </div>
          ) : (
            <AnimatePresence mode="popLayout">
              <div className="space-y-2">
                {filtered.map((opp, i) => (
                  <motion.div key={opp.id} layout
                    initial={{ opacity: 0, y: 8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -8 }}
                    transition={{ duration: 0.15, delay: Math.min(i * 0.02, 0.2) }}>
                    <ArbCard opp={opp} />
                  </motion.div>
                ))}
              </div>
            </AnimatePresence>
          )}
        </div>
      </ScrollArea>

      {/* Footer */}
      <div className="px-3 py-1 border-t border-zinc-800/50 text-[9px] text-zinc-600 text-center">
        Mid-market indicative prices · Title-similarity matching · Not financial advice
      </div>
    </div>
  );
}

export default App;
